  71→const getSnippetMetrics = (snippet, stageWidth) => {
  72→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  73→    const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
  74→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
  75→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  76→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  77→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
  78→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
  79→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
